#[tokio::main]
async fn main() -&gt; Result&lt;()&gt; {
    let prom = PrometheusSDK::new().await?;

    // Query the AI
    let response = prom.ai()
        .query("What is my CPU usage?")
        .await?;
    println!("AI: {}", response);

    // Get system info
    let mem = prom.system().memory().await?;
    println!("Memory: {:.1}% used", mem.percent_used);

    Ok(())
}
