async def main():
    prom = await PrometheusSDK.create()

    # Query the AI
    response = await prom.ai.query("What's on workspace 2?")
    print(f"AI: {response}")

    # Get system info
    cpu = await prom.system.cpu()
    print(f"CPU: {cpu.usage_percent:.1f}%")

asyncio.run(main())
